def gen(rng, size):
    n = rng.randint(0, max(0, min(size, 2000)))
    if n == 0:
        return [[]]
    arr = [rng.randint(0, 3)]
    for _ in range(n - 1):
        arr.append(rng.randint(0, 3) if rng.random() < 0.75 else None)
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

