class Solution:
    def longestUnivaluePath(self, root):
        self.best = 0
        def arm(node, parent_val):
            # returns longest downward equal-value arm length (edges) from node
            # that also equals parent_val (so parent can extend through node)
            if node is None:
                return 0
            left = arm(node.left, node.val)
            right = arm(node.right, node.val)
            self.best = max(self.best, left + right)
            if node.val == parent_val:
                return 1 + max(left, right)
            return 0
        if root is None:
            return 0
        # sentinel parent value that never matches a real node would miss; use root's own
        arm(root, root.val + 100000)
        return self.best

