class Solution:
    def longestUnivaluePath(self, root):
        self.best = 0
        def dfs(node):
            if node is None:
                return 0
            l = dfs(node.left)
            r = dfs(node.right)
            left_arm = l + 1 if node.left and node.left.val == node.val else 0
            right_arm = r + 1 if node.right and node.right.val == node.val else 0
            self.best = max(self.best, left_arm + right_arm)
            return max(left_arm, right_arm)
        dfs(root)
        return self.best

